mapper.select:
select config_group_id, product_id, group_name, group_type, is_required, is_multiple, sort_order, create_time, update_time
from sys_product_config_group
where config_group_id = #{configGroupId}

mapper.update:
update sys_product_config_group
group_name = #{groupName}, group_type = #{groupType}, is_required = #{isRequired}, is_multiple = #{isMultiple}, sort_order = #{sortOrder}, update_time = sysdate()
where config_group_id = #{configGroupId}
